content.script:
@if variables.woman.final_response_type == "open"
  ::Woman:: I knew you would come back. In my heart, I always knew.
  ::Woman:: You unlocked ${variables.player.memories_count} memories today.

  @if variables.woman.final_gift_ready == true
    ::Woman:: This is for you. The pendant. It matches mine.
    @set variables.woman.final_gift_ready = false
  @endif

@else
  @if variables.woman.final_response_type == "guarded"
    ::Woman:: You came, but you're still afraid.
    ::Woman:: The garden will wait for when you're ready.
  @else
    ::Woman:: I don't know you anymore.
  @endif

@endif

::Narrator:: The garden fades around you.
::Narrator:: You carry ${variables.player.memories_count} memories forward.
::Narrator:: Her trust in you: ${variables.woman.trust_level} out of 10.

@if variables.player.memory_locket_found == true
  ::Narrator:: The locket rests in your pocket. A key to the past.
@endif

@if variables.player.path == "direct"
  ::Woman:: A direct approach. I respect that.
  ::Woman:: You want the truth, even if it's painful.
  @set variables.woman.trust_level += 2
@endif

@if variables.player.path == "empathy"
  ::Woman:: You have a gentle heart. I can feel it.
  ::Woman:: That means more to me than you know.
  @set variables.woman.trust_level += 3
  @set variables.woman.mood = "warm"
@endif

@if variables.player.path == "intuitive"
  ::Woman:: You sense something, don't you?
  ::Woman:: Some part of you remembers.
  @set variables.woman.trust_level += 1
  @set variables.player.memories_count += 1
@endif

::Narrator:: The moment deepens. There is something more to discover.

::Woman:: You finally came.
::Player:: I... have we met before?

@if variables.player.approach == "open"
  ::Narrator:: She smiles slightly. You walked toward her without hesitation.
  @set variables.woman.trust_level += 1
@else
  @if variables.player.approach == "cautious"
    ::Narrator:: She notices your careful steps. Respect, maybe. Or fear.
  @else
    @if variables.player.approach == "distant"
      ::Narrator:: You keep your distance. She waits patiently.
      @set variables.woman.trust_level -= 1
    @endif
  @endif
@endif

@if variables.player.intuition >= 7
  ::Narrator:: Something about her voice feels familiar.
@else
  ::Narrator:: Her face is a blur you cannot place.
@endif

@if variables.player.courage >= 7
  ::Player:: Tell me the truth. Even if it hurts.
  @set variables.woman.trust_level += 2
@else
  ::Player:: I don't want to pretend. I really don't remember.
  @set variables.woman.trust_level -= 1
@endif

@if variables.player.empathy >= 7
  ::Player:: You look tired. Have you been waiting long?
  @set variables.woman.mood = "warm"
@else
  ::Player:: I should probably go.
  @set variables.woman.mood = "distant"
@endif

::Narrator:: The garden trembles. A choice crystallizes in the air.

@if variables.woman.trust_level >= 8
  ::Narrator:: She looks at you with complete recognition.
  @set variables.woman.final_gift_ready = true

  @if variables.player.empathy >= 8
    ::Narrator:: Ending: Reunion
  @else
    ::Narrator:: Ending: Understanding
  @endif

@else
  @if variables.player.courage >= 8
    ::Narrator:: Ending: Brave Parting
  @else
    ::Narrator:: Ending: Fade Away
  @endif

@endif

@if variables.player.memory_echo_encountered == true
  ::Narrator:: The echo fades, carrying your answer with it.
@else
  ::Narrator:: The memory remains locked within the garden.
@endif

@set variables.player.courage = 5
@set variables.player.intuition = 5
@set variables.player.empathy = 5
@set variables.player.gold = 20

@set variables.player.memories_count = 0
@set variables.player.memory_locket_found = false
@set variables.player.memory_echo_encountered = false

@set variables.woman.mood = "neutral"
@set variables.woman.trust_level = 4
@set variables.woman.final_response_type = "unsure"

::Narrator:: The air thickens. The garden folds inward like a dream.
::Woman:: This is where you left part of yourself.

@if variables.player.memories_count >= 2
  ::Narrator:: A doorway opens. You step into a room of light.
  @set variables.player.memory_echo_encountered = true

  @if variables.player.empathy >= 7
    ::Memory Echo:: You remembered me because you cared.
    @set variables.woman.trust_level += 2
  @else
    ::Memory Echo:: You remembered me because you were afraid to forget.
    @set variables.woman.trust_level -= 1
  @endif

@else
  ::Narrator:: The doorway stays sealed. You are not ready.
  @set variables.woman.mood = "distant"
@endif

@if variables.player.courage >= 7
  ::Player:: I’ll face it, even if it breaks me.
  @set variables.woman.final_response_type = "open"
@else
  ::Player:: I’m not sure I can.
  @set variables.woman.final_response_type = "guarded"
@endif
